 _phGauge(value){const min=Number(this.config.ph_min||6.8),max=Number(this.config.ph_max||7.8),pct=this._pct(value,min,max),end=-135+pct*270,status=this._phStatus(value),p=this._polar(70,70,54,end);return`<div class="gauge ph-gauge"><svg viewBox="0 0 140 140" class="ph-svg"><path class="ph-track" d="${this._arc(70,70,54,-135,135)}"/><path class="ph-progress" d="${this._arc(70,70,54,-135,end)}"/><circle class="ph-dot" cx="${p.x}" cy="${p.y}" r="10"/><text x="70" y="78" text-anchor="middle">${value||'—'}</text></svg><div class="gauge-label">pH</div><div class="pill ${this._qualityClass(status)}">${this._statusIcon(status)}${this._labelState(status)}</div></div>`}
 _chlorineGauge(){const raw=this._num(this.config.chlorine_entity)??this._num(this.config.orp_entity),isChl=Boolean(this.config.chlorine_entity),min=Number(isChl?this.config.chlorine_min:this.config.orp_min)||(isChl?0:400),max=Number(isChl?this.config.chlorine_max:this.config.orp_max)||(isChl?5:900),pct=raw===null?.5:Math.max(0,Math.min(1,(raw-min)/(max-min))),angle=-112+pct*224,status=this._chlStatus(),label=isChl?'Chlore':'RedOx';let ticks='';for(let i=0;i<13;i++){const a=-112+i*(224/12),p1=this._polar(70,70,50,a),p2=this._polar(70,70,i%3===0?37:43,a);ticks+=`<line x1="${p1.x}" y1="${p1.y}" x2="${p2.x}" y2="${p2.y}"/>`}return`<div class="gauge chlorine-gauge"><svg viewBox="0 0 140 140" class="speed-svg"><path class="speed-track" d="${this._arc(70,70,50,-112,112)}"/><g class="ticks">${ticks}</g><line class="speed-needle" x1="70" y1="70" x2="70" y2="28" style="transform:rotate(${angle}deg);transform-origin:70px 70px"/><circle class="hub" cx="70" cy="70" r="5"/></svg><div class="gauge-label">${label}</div><div class="pill ${this._qualityClass(status)}">${this._statusIcon(status)}${this._labelState(status)}</div></div>`}
