 _ensureWeatherForecast(){const e=this.config?.weather_entity;if(!e||!this._hass||this._forecastLoading===e)return;const fromAttr=this._forecastFromAttributes();if(fromAttr){this._weatherNextState=fromAttr;return}this._forecastLoading=e;const loadWs=async(type)=>{try{const r=await this._hass.callWS({type:'weather/forecast',entity_id:e,forecast_type:type});return this._pickForecastCondition(r,e)}catch(err){}try{const r=await this._hass.callWS({type:'weather/get_forecasts',entity_ids:[e],forecast_type:type});return this._pickForecastCondition(r,e)}catch(err){}try{const r=await this._hass.callWS({type:'weather/get_forecasts',entity_id:e,forecast_type:type});return this._pickForecastCondition(r,e)}catch(err){}try{const r=await this._hass.callWS({type:'execute_script',sequence:[{service:'weather.get_forecasts',target:{entity_id:e},data:{type:type},response_variable:'forecast'}]});return this._pickForecastCondition(r?.forecast||r,e)}catch(err){}return''};Promise.resolve().then(async()=>{const next=await loadWs('hourly')||await loadWs('daily')||await loadWs('twice_daily');this._weatherNextState=next||this._state(e)?.state||'';this._weatherForecastTried=true;if(!this._panel)this.render();this._forecastLoading=null})}
